content:
{
  "dialogues": [
    {
      "title": "遲到的原因",
      "turns": [
        {
          "speaker": "A",
          "text": "不好意思，我遲到了。",
          "pinyin": "Bù hǎo yìsi, wǒ chídào le.",
          "pinyin_numeric": "Bu4 hao3 yi4 si5, wo3 chi2 dao4 le5.",
          "translation_en": "Sorry, I'm late.",
          "translation_ko": "죄송합니다. 늦었어요."
        },
        {
          "speaker": "B",
          "text": "沒關係。你為什麼遲到？",
          "pinyin": "Méi guānxi. Nǐ wèishénme chídào?",
          "pinyin_numeric": "Mei2 guan1 xi5. Ni3 wei4 shen2 me5 chi2 dao4?",
          "translation_en": "No problem. Why are you late?",
          "translation_ko": "괜찮아요. 왜 늦었어요?"
        },
        {
          "speaker": "A",
          "text": "因為路上塞車了，所以來不及。",
          "pinyin": "Yīnwèi lùshàng sāichē le, suǒyǐ láibují.",
          "pinyin_numeric": "Yin1 wei4 lu4 shang4 sai1 che1 le5, suo3 yi3 lai2 bu5 ji2.",
          "translation_en": "Because there was a traffic jam on the road, so I couldn't make it in time.",
          "translation_ko": "길이 막혀서 제때 올 수 없었어요."
        },
        {
          "speaker": "B",
          "text": "原來是這樣。沒關係，我們開始吧。",
          "pinyin": "Yuánlái shì zhèyàng. Méi guānxi, wǒmen kāishǐ ba.",
          "pinyin_numeric": "Yuan2 lai2 shi4 zhe4 yang4. Mei2 guan1 xi5, wo3 men5 kai1 shi3 ba5.",
          "translation_en": "I see. No problem, let's start.",
          "translation_ko": "그렇군요. 괜찮아요. 시작합시다."
        }
      ],
      "comprehension_questions": [
        {
          "question_en": "Why was A late?",
          "question_ko": "A는 왜 늦었습니까?",
          "options_en": ["Because he forgot the time", "Because there was a traffic jam", "Because he was sick"],
          "options_ko": ["시간을 잊어서", "길이 막혀서", "아파서"],
          "correct_index": 1
        }
      ],
      "shadowing_prompt": "Repeat each sentence after the speaker, focusing on the tone of apology and explanation.",
      "free_response_prompt": "Tell a partner why you were late for a meeting. Use 因為 and 所以."
    },
    {
      "title": "不想吃的原因",
      "turns": [
        {
          "speaker": "A",
          "text": "你為什麼不想吃午餐？",
          "pinyin": "Nǐ wèishénme bù xiǎng chī wǔcān?",
          "pinyin_numeric": "Ni3 wei4 shen2 me5 bu4 xiang3 chi1 wu3 can1?",
          "translation_en": "Why don't you want to eat lunch?",
          "translation_ko": "왜 점심을 먹고 싶지 않아요?"
        },
        {
          "speaker": "B",
          "text": "因為我早上吃太多了，現在肚子不餓。",
          "pinyin": "Yīnwèi wǒ zǎoshàng chī tài duō le, xiànzài dùzi bù è.",
          "pinyin_numeric": "Yin1 wei4 wo3 zao3 shang4 chi1 tai4 duo1 le5, xian4 zai4 du4 zi5 bu4 e4.",
          "translation_en": "Because I ate too much this morning, I'm not hungry now.",
          "translation_ko": "아침에 너무 많이 먹어서 지금 배가 고프지 않아요."
        },
        {
          "speaker": "A",
          "text": "原來是這樣。那你想喝什麼嗎？",
          "pinyin": "Yuánlái shì zhèyàng. Nà nǐ xiǎng hē shénme ma?",
          "pinyin_numeric": "Yuan2 lai2 shi4 zhe4 yang4. Na4 ni3 xiang3 he1 shen2 me5 ma5?",
          "translation_en": "I see. Do you want to drink something?",
          "translation_ko": "그렇군요. 그럼 뭘 마시고 싶어요?"
        },
        {
          "speaker": "B",
          "text": "好，我想喝一杯紅茶，少冰。",
          "pinyin": "Hǎo, wǒ xiǎng hē yī bēi hóngchá, shǎo bīng.",
          "pinyin_numeric": "Hao3, wo3 xiang3 he1 yi1 bei1 hong2 cha2, shao3 bing1.",
          "translation_en": "Okay, I'd like a cup of black tea, less ice.",
          "translation_ko": "네, 홍차 한 잔에 얼음 적게 주세요."
        }
      ],
      "comprehension_questions": [
        {
          "question_en": "Why doesn't B want to eat lunch?",
          "question_ko": "B는 왜 점심을 먹고 싶지 않습니까?",
          "options_en": ["Because he is sick", "Because he ate too much in the morning", "Because he wants to save money"],
          "options_ko": ["아파서", "아침에 너무 많이 먹어서", "돈을 아끼고 싶어서"],
          "correct_index": 1
        }
      ],
      "shadowing_prompt": "Repeat each sentence after the speaker, focusing on the tone of refusal and suggestion.",
      "free_response_prompt": "Tell a friend why you don't want to eat now. Use 因為 and 所以."
    },
    {
      "title": "想買的原因",
      "turns": [
        {
          "speaker": "A",
          "text": "你為什麼想買這個手機？",
          "pinyin": "Nǐ wèishénme xiǎng mǎi zhège shǒujī?",
          "pinyin_numeric": "Ni3 wei4 shen2 me5 xiang3 mai3 zhe4 ge5 shou3 ji1?",
          "translation_en": "Why do you want to buy this phone?",
          "translation_ko": "왜 이 핸드폰을 사고 싶어요?"
        },
        {
          "speaker": "B",
          "text": "因為我的手機太舊了，而且這個比較便宜。",
          "pinyin": "Yīnwèi wǒ de shǒujī tài jiù le, érqiě zhège bǐjiào piányí.",
          "pinyin_numeric": "Yin1 wei4 wo3 de5 shou3 ji1 tai4 jiu4 le5, er2 qie3 zhe4 ge5 bi3 jiao4 pian2 yi2.",
          "translation_en": "Because my phone is too old, and this one is cheaper.",
          "translation_ko": "제 핸드폰이 너무 오래됐고, 이게 더 싸거든요."
        },
        {
          "speaker": "A",
          "text": "原來是這樣。你想省錢，對嗎？",
          "pinyin": "Yuánlái shì zhèyàng. Nǐ xiǎng shěng qián, duì ma?",
          "pinyin_numeric": "Yuan2 lai2 shi4 zhe4 yang4. Ni3 xiang3 sheng3 qian2, dui4 ma5?",
          "translation_en": "I see. You want to save money, right?",
          "translation_ko": "그렇군요. 돈을 아끼고 싶은 거죠?"
        },
        {
          "speaker": "B",
          "text": "對，而且這個手機也很好用。",
          "pinyin": "Duì, érqiě zhège shǒujī yě hěn hǎo yòng.",
          "pinyin_numeric": "Dui4, er2 qie3 zhe4 ge5 shou3 ji1 ye3 hen3 hao3 yong4.",
          "translation_en": "Yes, and this phone is also very easy to use.",
          "translation_ko": "네, 그리고 이 핸드폰도 사용하기 좋아요."
        }
      ],
      "comprehension_questions": [
        {
          "question_en": "Why does B want to buy the new phone?",
          "question_ko": "B는 왜 새 핸드폰을 사고 싶습니까?",
          "options_en": ["Because it is new and expensive", "Because his old phone is too old and this one is cheaper", "Because he lost his phone"],
          "options_ko": ["새롭고 비싸서", "예전 핸드폰이 너무 오래됐고 이게 더 싸서", "핸드폰을 잃어버려서"],
          "correct_index": 1
        }
      ],
      "shadowing_prompt": "Repeat each sentence after the speaker, focusing on the tone of explanation and agreement.",
      "free_response_prompt": "Tell a friend why you want to buy something. Use 因為 and 所以."
    }
  ]
}
